import styled from 'styled-components';

export const NavContainer = styled.nav`
background-color:#50A6D8;

hr {
    width:60%;
}


.navigation{
    list-style:none;
}

.navigation__link {
    font-weight:600;
    font-size:1.5em;
    position:relative;
    display:inline-flex;
    z-index: 1;
    color:rgb(255,255,255);
    text-decoration:none;
}

.navigation__link:before {
    content: '';
    position:absolute;
    display:flex;
    bottom:0;
    left: -.75em;
    height:50%;
    width:0%;
    background:#403f4c;
    z-index:-1;
    transition: .3s;
}

.navigation__link:hover:before {
    width: calc(100% + 1.5em);
}

@media only screen and (max-width: 900px) {
    .navigation{
        display:flex;
        flex-direction:row;
        justify-content:space-evenly;
        align-items:center;
        width:100%;
        gap:1em;
        padding:1em;
        margin:0;
    }

    .navigation__item {
        display:flex;
        justify-content:space-between;
    }

    hr {
        display:none;
    }
}
`
